external_knowledge:
- "golden eagle" is a metaphor for a champion or the best player;
- "soaring above the rest" refers to having a higher average prize money than others;
- "average pot winnings" corresponds to the average prize money earned by the player in their victorious tournaments;
- "claimed the title of champion on numerous occasions" means the player has won multiple tournaments.

sql:
SELECT COUNT(*) AS total_players
FROM players
WHERE pro_status = 1 AND country = 'USA';

SELECT player_name
FROM players
WHERE player_id < 100 AND pro_status = 1;

SELECT AVG(putts_made) AS average_putts_last_5_years
FROM putting_stats
WHERE year >= (strftime('%Y', 'now') - 5);

